    function normalizeBrazilState(value = '') {
      const raw = String(value || '').trim();
      if (!raw) return '';
      const upper = raw.toUpperCase();
      if (BRAZIL_STATE_CITIES[upper]) return upper;
      const normalized = normalize(raw);
      const found = Object.entries(BRAZIL_STATE_NAMES).find(([, name]) => normalize(name) === normalized);
      return found ? found[0] : upper.slice(0, 2);
    }

    function brazilStateOptions(selected = '') {
      const uf = normalizeBrazilState(selected);
      return `<option value="">Selecione o estado...</option>` + Object.keys(BRAZIL_STATE_CITIES).map(key =>
        `<option value="${key}" ${uf === key ? 'selected' : ''}>${key} - ${escapeHtml(BRAZIL_STATE_NAMES[key])}</option>`
      ).join('');
    }

    function cityOptionsByState(stateValue = '', selectedCity = '') {
      const uf = normalizeBrazilState(stateValue);
      const selected = String(selectedCity || '').trim();
      const cities = BRAZIL_STATE_CITIES[uf] || [];
      const extra = selected && !cities.some(city => normalize(city) === normalize(selected)) ? [selected] : [];
      return `<option value="">Selecione a cidade...</option>` + [...extra, ...cities].map(city =>
        `<option value="${escapeAttr(city)}" ${normalize(selected) === normalize(city) ? 'selected' : ''}>${escapeHtml(city)}</option>`
      ).join('');
    }

    function bindStateCitySelects(stateSelector, citySelector) {
      const stateEl = document.querySelector(stateSelector);
      const cityEl = document.querySelector(citySelector);
      if (!stateEl || !cityEl) return;
      const refresh = () => {
        const previous = cityEl.value;
        cityEl.innerHTML = cityOptionsByState(stateEl.value, previous);
      };
      stateEl.addEventListener('change', () => {
        cityEl.innerHTML = cityOptionsByState(stateEl.value, '');
      });
      refresh();
    }

