    function uid(prefix = 'id') {
      return prefix + '_' + Math.random().toString(36).slice(2, 9) + '_' + Date.now().toString(36);
    }

    function todayISO() {
      const d = new Date();
      return toISODate(d);
    }

    function toISODate(date) {
      const y = date.getFullYear();
      const m = String(date.getMonth() + 1).padStart(2, '0');
      const d = String(date.getDate()).padStart(2, '0');
      return `${y}-${m}-${d}`;
    }

    function brDate(iso) {
      if (!iso) return '—';
      const dateOnly = followupDateOnly(iso) || String(iso || '').split('T')[0];
      const [y, m, d] = String(dateOnly || '').split('-');
      if (!y || !m || !d) return iso;
      return `${d}/${m}/${y}`;
    }

    function brDateTime(value) {
      if (!value) return '—';
      const d = parseFollowupDateTime(value) || new Date(value);
      if (Number.isNaN(d.getTime())) return brDate(value);
      return d.toLocaleString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    }

    function hasFollowupExplicitTime(value) {
      const raw = String(value || '').trim();
      if (!raw) return false;
      if (/T\d{2}:\d{2}/.test(raw)) return true;
      if (/\b\d{1,2}:\d{2}\b/.test(raw)) return true;
      if (/\b\d{1,2}\s*h(?:\s*\d{0,2})?\b/i.test(raw)) return true;
      return false;
    }

    function parseFollowupTimeParts(text) {
      const raw = String(text || '').trim();
      if (!raw) return null;
      let match = raw.match(/(?:T|\s|às|as|,|-)\s*(\d{1,2}):(\d{2})\b/i) || raw.match(/\b(\d{1,2}):(\d{2})\b/);
      if (match) {
        const hour = Number(match[1]);
        const minute = Number(match[2]);
        if (hour >= 0 && hour <= 23 && minute >= 0 && minute <= 59) return { hour, minute };
      }
      match = raw.match(/\b(\d{1,2})\s*h\s*(\d{1,2})?\b/i);
      if (match) {
        const hour = Number(match[1]);
        const minute = match[2] ? Number(match[2]) : 0;
        if (hour >= 0 && hour <= 23 && minute >= 0 && minute <= 59) return { hour, minute };
      }
      return null;
    }

    function parseFollowupDateTime(value) {
      const raw = String(value || '').trim();
      if (!raw) return null;

      let match = raw.match(/^(\d{4})-(\d{2})-(\d{2})(?:[T\s](\d{2}):(\d{2})(?::(\d{2}))?)?/);
      if (match) {
        const year = Number(match[1]);
        const month = Number(match[2]) - 1;
        const day = Number(match[3]);
        const hour = match[4] !== undefined ? Number(match[4]) : 0;
        const minute = match[5] !== undefined ? Number(match[5]) : 0;
        const second = match[6] !== undefined ? Number(match[6]) : 0;
        const date = new Date(year, month, day, hour, minute, second, 0);
        return Number.isNaN(date.getTime()) ? null : date;
      }

      match = raw.match(/\b(\d{1,2})\/(\d{1,2})(?:\/(\d{2,4}))?\b/);
      if (match) {
        const today = new Date();
        const day = Number(match[1]);
        const month = Number(match[2]) - 1;
        let year = match[3] ? Number(match[3]) : today.getFullYear();
        if (year < 100) year += 2000;
        const time = parseFollowupTimeParts(raw) || { hour: 0, minute: 0 };
        const date = new Date(year, month, day, time.hour, time.minute, 0, 0);
        return Number.isNaN(date.getTime()) ? null : date;
      }

      const parsed = new Date(raw);
      return Number.isNaN(parsed.getTime()) ? null : parsed;
    }

    function normalizeFollowupInputValue(value) {
      const raw = String(value || '').trim();
      if (!raw) return '';
      const date = parseFollowupDateTime(raw);
      if (!date) return raw;
      const datePart = toISODate(date);
      if (!hasFollowupExplicitTime(raw)) return datePart;
      const hour = String(date.getHours()).padStart(2, '0');
      const minute = String(date.getMinutes()).padStart(2, '0');
      return `${datePart}T${hour}:${minute}`;
    }

    function followupInputValue(value) {
      const raw = String(value || '').trim();
      if (!raw) return '';
      const date = parseFollowupDateTime(raw);
      if (!date) return '';
      const datePart = toISODate(date);
      const hour = hasFollowupExplicitTime(raw) ? date.getHours() : 9;
      const minute = hasFollowupExplicitTime(raw) ? date.getMinutes() : 0;
      return `${datePart}T${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
    }

    function followupDateOnly(value) {
      const date = parseFollowupDateTime(value);
      return date ? toISODate(date) : '';
    }

    function isFollowupDue(value, now = new Date()) {
      const date = parseFollowupDateTime(value);
      if (!date) return false;
      return date.getTime() <= now.getTime();
    }

    function isFollowupToday(value, now = new Date()) {
      const date = parseFollowupDateTime(value);
      if (!date) return false;
      return date.getFullYear() === now.getFullYear()
        && date.getMonth() === now.getMonth()
        && date.getDate() === now.getDate();
    }

    function isFollowupPendingLaterToday(value, now = new Date()) {
      const date = parseFollowupDateTime(value);
      if (!date) return false;
      return isFollowupToday(value, now) && date.getTime() > now.getTime();
    }

    function combineFollowupDateWithExistingTime(dateIso, existingValue = '') {
      const rawDate = String(dateIso || '').trim();
      if (!rawDate) return '';
      const [year, month, day] = rawDate.split('-').map(Number);
      if (!year || !month || !day) return rawDate;
      const existing = parseFollowupDateTime(existingValue);
      if (existing && hasFollowupExplicitTime(existingValue)) {
        return `${rawDate}T${String(existing.getHours()).padStart(2, '0')}:${String(existing.getMinutes()).padStart(2, '0')}`;
      }
      return rawDate;
    }

    function compareFollowupDateTime(a, b) {
      const da = parseFollowupDateTime(a);
      const dbDate = parseFollowupDateTime(b);
      const ta = da ? da.getTime() : Number.MAX_SAFE_INTEGER;
      const tb = dbDate ? dbDate.getTime() : Number.MAX_SAFE_INTEGER;
      return ta - tb;
    }

    function formatFollowupDateTime(value) {
      if (!value) return '—';
      const date = parseFollowupDateTime(value);
      if (!date) return '—';
      const now = new Date();
      const tomorrow = new Date(now);
      tomorrow.setDate(now.getDate() + 1);
      const hasTime = hasFollowupExplicitTime(value);
      const time = `${String(date.getHours()).padStart(2, '0')}:${String(date.getMinutes()).padStart(2, '0')}`;
      const base = isFollowupToday(value, now)
        ? 'Hoje'
        : (date.getFullYear() === tomorrow.getFullYear() && date.getMonth() === tomorrow.getMonth() && date.getDate() === tomorrow.getDate())
          ? 'Amanhã'
          : brDate(toISODate(date));
      return hasTime ? `${base} às ${time}` : `${base} (sem horário)`;
    }

    function money(value) {
      return Number(value || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
    }

    function saveDb() {
      const payload = JSON.stringify(db);
      try {
        localStorage.setItem(STORAGE_KEY, payload);
        return true;
      } catch (e) {
        console.warn('Primeira tentativa de salvar no localStorage falhou. Tentando sobrescrever a base antiga.', e);
        try {
          // Em alguns navegadores, substituir uma base antiga pesada por uma base menor pode falhar
          // se o navegador calcular o tamanho antes de remover o valor anterior.
          // Para restauração de backup, removemos a chave antiga e gravamos novamente.
          localStorage.removeItem(STORAGE_KEY);
          localStorage.setItem(STORAGE_KEY, payload);
          return true;
        } catch (secondError) {
          console.error('Erro ao salvar no localStorage.', secondError);
          if (typeof toast === 'function') toast('Não foi possível salvar os dados no navegador. A base pode estar grande demais. Baixe um backup restaurável e remova áudios antigos.', 'error');
          return false;
        }
      }
    }

    function loadDb() {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored) {
        try {
          const parsed = JSON.parse(stored);
          return migrateDb(parsed);
        } catch (e) {
          console.warn('Erro ao ler localStorage. Recriando seed.', e);
        }
      }
      const seed = createSeed();
      localStorage.setItem(STORAGE_KEY, JSON.stringify(seed));
      return seed;
    }

    function migrateLegacyResultLabel(result) {
      const map = {
        'Ligar Novamente': 'Ligar Novamente',
        'Agendou': 'Reunião Marcada',
        'Ocupado': 'Follow-up',
        'Não atendeu': 'Ligar Novamente',
        'Oportunidade': 'Reunião Marcada',
        'Convertido': 'Reunião Marcada',
        'Conversou': 'Falar com decisor'
      };
      return map[result] || result || '';
    }

    function migrateDb(data) {
      if (data && data._formattedEmptyBase) {
        const fallbackUser = { id: 'u_admin', name: 'Guilherme', email: 'admin@buyflow.com', password: '123456', role: 'gestor', campaigns_allowed: [] };
        const cleanUsers = Array.isArray(data.users) && data.users.length ? data.users : [fallbackUser];
        return {
          _formattedEmptyBase: true,
          _formattedAt: data._formattedAt || '',
          campaigns: Array.isArray(data.campaigns) ? data.campaigns : [],
          leads: [],
          callLogs: [],
          followUps: [],
          meetings: [],
          goals: [],
          users: cleanUsers.map(user => ({
            id: user.id || 'u_admin',
            name: user.name || 'Guilherme',
            email: user.email || 'admin@buyflow.com',
            password: user.password || '123456',
            role: user.role || 'gestor',
            campaigns_allowed: user.role === 'gestor' ? [] : []
          })),
          activities: [],
          importBatches: [],
          importSnapshots: [],
          importConflicts: [],
          orphanAudios: [],
          systemHistory: [],
          settings: data.settings && typeof data.settings === 'object' ? { ...data.settings, history: [], lastBackupAt: '', lastImportAt: '' } : { profile: {}, appearance: {}, history: [], lastBackupAt: '', lastImportAt: '' }
        };
      }
      const seed = createSeed();
      const migrated = { ...seed, ...data };
      migrated.campaigns = Array.isArray(data.campaigns) && data.campaigns.length ? data.campaigns : seed.campaigns;

      const generalCampaign = seed.campaigns.find(c => c.id === 'camp_general');
      if (generalCampaign && !migrated.campaigns.some(c => c.id === 'camp_general')) {
        migrated.campaigns.unshift(generalCampaign);
      }

      migrated.leads = (data.leads || seed.leads).map((lead, index) => ({
        ...lead,
        campaign_id: lead.campaign_id || 'camp_general',
        lead_source: lead.lead_source || 'Importado',
        last_origin_campaign: lead.last_origin_campaign || lead.campaign_id || 'camp_general',
        estimated_value: Number(lead.estimated_value || lead.value || 0),
        imported_at: lead.imported_at || lead.created_at || '',
        import_batch_id: lead.import_batch_id || '',
        moved_at: lead.moved_at || '',
        moved_from_campaign_id: lead.moved_from_campaign_id || '',
        moved_to_campaign_id: lead.moved_to_campaign_id || '',
        city: lead.city || lead.cidade || '',
        state: lead.state || lead.uf || lead.estado || '',
        attendant_name: lead.attendant_name || '',
        owner_name: lead.owner_name || '',
        last_result: migrateLegacyResultLabel(lead.last_result),
        last_comments: ['Lead ainda não abordado.', 'Conversou bem. Vale retomar com diagnóstico da jornada.'].includes(lead.last_comments) ? '' : (lead.last_comments || ''),
        diagnostic_data: migrateDiagnosticData(lead.diagnostic_data || {}),
        call_transcript: lead.call_transcript || lead.diagnostic_data?.transcript || '',
        call_audio: lead.call_audio ? {
          ...lead.call_audio,
          type: 'audio/mpeg',
          data_url: String(lead.call_audio.data_url || '').startsWith('data:audio')
            ? lead.call_audio.data_url
            : (String(lead.call_audio.data_url || '').includes(',') ? `data:audio/mpeg;base64,${String(lead.call_audio.data_url || '').split(',').pop()}` : lead.call_audio.data_url)
        } : null
      }));
      migrated.callLogs = data.callLogs || [];
      migrated.followUps = data.followUps || [];
      migrated.meetings = (data.meetings || []).map(meeting => ({
        ...meeting,
        id: meeting.id || uid('meet'),
        lead_id: meeting.lead_id || '',
        campaign_id: meeting.campaign_id || 'camp_general',
        owner_id: meeting.owner_id || 'u_admin',
        call_id: meeting.call_id || '',
        meeting_date: meeting.meeting_date || meeting.scheduled_date || meeting.date || '',
        meeting_time: meeting.meeting_time || meeting.time || '',
        status: meeting.status || 'Marcada',
        notes: meeting.notes || meeting.first_meeting_notes || '',
        happened: meeting.happened || meeting.what_happened || '',
        next_meeting_date: meeting.next_meeting_date || '',
        next_meeting_time: meeting.next_meeting_time || '',
        next_meeting_notes: meeting.next_meeting_notes || '',
        result: meeting.result || '',
        created_at: meeting.created_at || new Date().toISOString(),
        updated_at: meeting.updated_at || ''
      }));
      migrated.importBatches = data.importBatches || [];
      migrated.goals = Array.isArray(data.goals) ? data.goals.map(goal => ({
        ...goal,
        id: goal.id || uid('goal'),
        type: goal.type || 'calls',
        target: Number(goal.target || goal.targetValue || 0),
        start_value: Number(goal.start_value || goal.startValue || 0),
        period: goal.period || 'monthly',
        campaign_id: goal.campaign_id || goal.campaignId || 'all',
        owner_id: goal.owner_id || goal.ownerId || 'all',
        priority: goal.priority || 'media',
        color: goal.color || '#2563EB',
        status_manual: goal.status_manual || '',
        created_at: goal.created_at || new Date().toISOString(),
        updated_at: goal.updated_at || ''
      })) : [];
      migrated.users = Array.isArray(data.users) && data.users.length ? data.users : seed.users;
      migrated.users = migrated.users.map(user => ({
        ...user,
        campaigns_allowed: user.role === 'gestor'
          ? migrated.campaigns.map(c => c.id)
          : unique([...(user.campaigns_allowed || []), 'camp_general'])
      }));
      migrated.activities = data.activities || [];
      return migrated;
    }

