    function createEmptyFormattedDb() {
      const now = new Date().toISOString();
      const current = state?.currentUser || db?.users?.[0] || {};
      const profileSettings = db?.settings && typeof db.settings === 'object' ? db.settings : {};
      const cleanUser = {
        id: current.id || 'u_admin',
        name: current.name || profileSettings?.profile?.name || 'Guilherme',
        email: current.email || profileSettings?.profile?.email || 'admin@buyflow.com',
        password: current.password || '123456',
        role: 'gestor',
        campaigns_allowed: []
      };
      return {
        _formattedEmptyBase: true,
        _formattedAt: now,
        campaigns: [],
        leads: [],
        callLogs: [],
        followUps: [],
        meetings: [],
        goals: [],
        users: [cleanUser],
        activities: [],
        importBatches: [],
        importSnapshots: [],
        importConflicts: [],
        orphanAudios: [],
        systemHistory: [],
        settings: {
          profile: profileSettings.profile && typeof profileSettings.profile === 'object' ? { ...profileSettings.profile } : {},
          appearance: profileSettings.appearance && typeof profileSettings.appearance === 'object' ? { ...profileSettings.appearance } : {},
          history: [],
          lastBackupAt: '',
          lastImportAt: ''
        }
      };
    }

    function offsetDate(days) {
      const d = new Date();
      d.setDate(d.getDate() + days);
      return toISODate(d);
    }

    function currentUserIsAdmin() {
      return state.currentUser && state.currentUser.role === 'gestor';
    }

    function userAllowedCampaignIds(user = state.currentUser) {
      if (!user) return [];
      if (user.role === 'gestor') return db.campaigns.map(c => c.id);
      return user.campaigns_allowed || [];
    }

    function accessibleCampaigns() {
      const allowed = userAllowedCampaignIds();
      return db.campaigns.filter(c => allowed.includes(c.id));
    }

    function canAccessCampaign(campaignId) {
      return userAllowedCampaignIds().includes(campaignId);
    }

    function getCampaign(id) {
      return db.campaigns.find(c => c.id === id) || { id: '', name: 'Sem campanha', color: '#64748B', script: '' };
    }

    function getUser(id) {
      return db.users.find(u => u.id === id) || { name: '—', role: '—' };
    }

    function logActivity(text) {
      db.activities.unshift({ id: uid('act'), text, date: new Date().toISOString(), user_id: state.currentUser?.id || '' });
      db.activities = db.activities.slice(0, 50);
      saveDb();
    }

    function applyCuiabaMatoGrossoToCurrentLeads() {
      if (db._cuiabaMtPatchApplied) return;

      let changed = false;
      (db.leads || []).forEach(lead => {
        if (lead.city !== 'Cuiabá' || lead.state !== 'MT') {
          lead.city = 'Cuiabá';
          lead.state = 'MT';
          changed = true;
        }
      });

      db._cuiabaMtPatchApplied = new Date().toISOString();

      if (changed) {
        saveDb();
        logActivity(`Localização atualizada em massa: ${(db.leads || []).length} leads definidos como Cuiabá / MT.`);
      } else {
        saveDb();
      }
    }

    function applyFictitiousHoursToLeads() {
      const leads = db.leads || [];
      if (leads.length === 0) return;
      
      const schedules = [
        { mon: '11am-12am', tue: '11am-12am', wed: '11am-3am', thu: '11am-3am', fri: '11am-3am', sat: '11am-12am', sun: '11am-3am' },
        { mon: '08am-06pm', tue: '08am-06pm', wed: '08am-06pm', thu: '08am-06pm', fri: '08am-06pm', sat: '09am-01pm', sun: 'Fechado' },
        { mon: '09am-07pm', tue: '09am-07pm', wed: '09am-07pm', thu: '09am-07pm', fri: '09am-07pm', sat: '10am-04pm', sun: '10am-02pm' },
        { mon: '10am-10pm', tue: '10am-10pm', wed: '10am-10pm', thu: '10am-10pm', fri: '10am-10pm', sat: '10am-11pm', sun: '12pm-08pm' }
      ];

      let changedCount = 0;
      leads.forEach((lead, index) => {
        const hasHours = lead.hours_monday || lead.hours_tuesday || lead.hours_sunday;
        if (!hasHours) {
          const schedule = schedules[index % schedules.length];
          lead.hours_monday = schedule.mon;
          lead.hours_tuesday = schedule.tue;
          lead.hours_wednesday = schedule.wed;
          lead.hours_thursday = schedule.thu;
          lead.hours_friday = schedule.fri;
          lead.hours_saturday = schedule.sat;
          lead.hours_sunday = schedule.sun;
          changedCount++;
        }
      });

      if (changedCount > 0) {
        saveDb();
        logActivity(`Horários de funcionamento fictícios adicionados a ${changedCount} leads.`);
      }
    }

    function init() {
      repairNoAnswerQueueState();
      if (!db._formattedEmptyBase) applyCuiabaMatoGrossoToCurrentLeads();
      
      if (!db._formattedEmptyBase && !db._sampleLeadsAdded && (!db.leads || db.leads.length === 0)) {
        const seed = createSeed();
        db.leads = seed.leads;
        db._sampleLeadsAdded = new Date().toISOString();
        saveDb();
      }

      if (!db._formattedEmptyBase) applyFictitiousHoursToLeads();
      applyTheme();
      bindGlobalEvents();
      renderLoginState();
    }

    function getStorageStats() {
      const data = JSON.stringify(db);
      const bytes = new Blob([data]).size;
      const mb = bytes / (1024 * 1024);
      const audioCount = (db.leads || []).filter(l => l.call_audio).length;
      const transcriptCount = (db.leads || []).filter(l => l.call_transcript || l.diagnostic_data?.transcript).length;
      return {
        bytes,
        mb,
        label: formatBytes(bytes),
        audioCount,
        transcriptCount
      };
    }

    function getDataHealth() {
      const leads = baseAccessibleLeads();
      const total = leads.length || 1;
      const withPhone = leads.filter(l => l.phone || l.whatsapp).length;
      const withCampaign = leads.filter(l => l.campaign_id && getCampaign(l.campaign_id)).length;
      const withFollowUp = leads.filter(l => l.next_followup).length;
      const contacted = getContactedLeads ? getContactedLeads().length : leads.filter(l => l.last_contact).length;
      const stats = getStorageStats();

      return [
        { label: 'Telefones na base', desc: `${withPhone}/${leads.length} leads com telefone ou WhatsApp`, score: Math.round((withPhone / total) * 100) },
        { label: 'Campanhas vinculadas', desc: `${withCampaign}/${leads.length} leads com campanha válida`, score: Math.round((withCampaign / total) * 100) },
        { label: 'Follow-ups marcados', desc: `${withFollowUp} leads com próximo retorno`, score: leads.length ? Math.min(100, Math.round((withFollowUp / total) * 100)) : 0 },
        { label: 'Contatos reais', desc: `${contacted} leads já atenderam ou tiveram conversa`, score: leads.length ? Math.min(100, Math.round((contacted / total) * 100)) : 0 },
        { label: 'Peso do navegador', desc: `${stats.label} salvos localmente • ${stats.audioCount} áudio(s)`, score: stats.mb < 3 ? 90 : stats.mb < 4.5 ? 60 : 25 }
      ];
    }

    function healthScoreClass(score) {
      if (score >= 75) return 'good';
      if (score >= 45) return 'warn';
      return 'bad';
    }

    function renderHealthList() {
      return `<div class="health-list">
        ${getDataHealth().map(item => `
          <div class="health-item">
            <div><strong>${escapeHtml(item.label)}</strong><br><span>${escapeHtml(item.desc)}</span></div>
            <div class="health-score ${healthScoreClass(item.score)}">${item.score}%</div>
          </div>
        `).join('')}
      </div>`;
    }

