      document.getElementById('clearLeadFilters').addEventListener('click', () => { state.leadFilters = { campaign: 'all', status: 'all', temperature: 'all', segment: 'all', search: '' }; renderLeads(); });
      document.getElementById('importBtn').addEventListener('click', openImportModal);
      const openUndoHistoryBtn = document.getElementById('openImportUndoHistoryBtn');
      if (openUndoHistoryBtn) {
        openUndoHistoryBtn.setAttribute('type', 'button');
        openUndoHistoryBtn.removeAttribute('download');
        openUndoHistoryBtn.removeAttribute('href');
        openUndoHistoryBtn.addEventListener('click', event => {
          event.preventDefault();
          event.stopPropagation();
          event.stopImmediatePropagation();
          if (!openUndoHistoryBtn.disabled) openImportHistoryModal();
          return false;
        }, true);
      }
      document.getElementById('newLeadBtn').addEventListener('click', () => openLeadModal());
      bindLeadTableActions();
      setupLeadStickyScroller();
