    function compactUrlLabel(url = '') {
      const value = String(url || '').trim();
      if (!value) return '';
      try {
        const normalized = /^https?:\/\//i.test(value) ? value : `https://${value}`;
        const parsed = new URL(normalized);
        return parsed.hostname.replace(/^www\./, '').replace(/^instagram\.com$/i, 'Instagram');
      } catch (e) {
        return value.replace(/^https?:\/\//i, '').replace(/^www\./i, '').split(/[/?#]/)[0] || value;
      }
    }

    function compactInstagramLabel(lead) {
      const social = parseLeadSocialMedia(lead);
      const raw = String(lead?.instagram || social.instagram || '').trim();
      if (!raw) return 'Insta';
      if (/instagram\.com/i.test(raw)) {
        const handle = raw.split('instagram.com/')[1]?.split(/[/?#]/)[0];
        return handle ? `@${handle.replace(/^@/, '')}` : 'Instagram';
      }
      return raw.startsWith('@') ? raw : `@${raw.replace(/^@/, '').split(/[/?#]/)[0]}`;
    }

    function leadLinkPill(label, url, title = '') {
      if (!url) return '';
      return `<a class="lead-link-pill external-link" target="_blank" rel="noopener noreferrer" href="${escapeAttr(url)}" title="${escapeAttr(title || label)}">${escapeHtml(label)}</a>`;
    }

    function renderCompactLeadLinks(lead) {
      const instagramUrl = getInstagramUrl(lead);
      const websiteUrl = getWebsiteUrl(lead);
      const mapsUrl = lead.google_maps || '';
      const links = [
        instagramUrl ? leadLinkPill(compactInstagramLabel(lead), instagramUrl, 'Abrir Instagram') : '',
        websiteUrl ? leadLinkPill(compactUrlLabel(websiteUrl) || 'Site', websiteUrl, 'Abrir site') : '',
        mapsUrl ? leadLinkPill('Maps', mapsUrl, 'Abrir Google Maps') : ''
      ].filter(Boolean);
      return links.length ? `<div class="lead-link-row">${links.join('')}</div>` : '<span class="lead-cell-line">Sem links</span>';
    }

    function yesNoCompact(value) {
      const text = String(value || '').trim();
      if (!text) return '—';
      if (/^(sim|yes|true|1)$/i.test(text)) return 'Sim';
      if (/^(não|nao|no|false|0)$/i.test(text)) return 'Não';
      return text;
    }

