    function cleanupLeadStickyScroller() {
      if (state._leadStickyResizeHandler) {
        window.removeEventListener('resize', state._leadStickyResizeHandler);
        state._leadStickyResizeHandler = null;
      }
      if (state.page !== 'leads') {
        document.querySelectorAll('#leadStickyScroller, .lead-sticky-scroll').forEach(el => {
          el.classList.add('hidden');
          el.style.display = 'none';
        });
      }
    }

    function setupLeadStickyScroller() {
      if (state.page !== 'leads') return;
      const wrap = document.getElementById('leadsCompactWrap');
      const sticky = document.getElementById('leadStickyScroller');
      const inner = document.getElementById('leadStickyScrollerInner');
      const table = wrap?.querySelector('.leads-compact-table');
      if (!wrap || !sticky || !inner || !table) return;

      let syncing = false;

      const refresh = () => {
        const tableWidth = table.scrollWidth || wrap.scrollWidth || 0;
        inner.style.width = `${tableWidth}px`;
        const shouldHide = tableWidth <= wrap.clientWidth + 6 || state.page !== 'leads';
        sticky.classList.toggle('hidden', shouldHide);
        sticky.style.display = shouldHide ? 'none' : '';
        sticky.scrollLeft = wrap.scrollLeft;
      };

      const syncFromWrap = () => {
        if (syncing) return;
        syncing = true;
        sticky.scrollLeft = wrap.scrollLeft;
        requestAnimationFrame(() => { syncing = false; });
      };

      const syncFromSticky = () => {
        if (syncing) return;
        syncing = true;
        wrap.scrollLeft = sticky.scrollLeft;
        requestAnimationFrame(() => { syncing = false; });
      };

      wrap.addEventListener('scroll', syncFromWrap, { passive: true });
      sticky.addEventListener('scroll', syncFromSticky, { passive: true });

      refresh();
      requestAnimationFrame(refresh);
      setTimeout(refresh, 250);

      if (state._leadStickyResizeHandler) {
        window.removeEventListener('resize', state._leadStickyResizeHandler);
      }
      state._leadStickyResizeHandler = refresh;
      window.addEventListener('resize', state._leadStickyResizeHandler, { passive: true });
    }

    function bindLeadTableActions() {
      document.querySelectorAll('[data-action]').forEach(btn => {
        btn.addEventListener('click', () => {
          const id = btn.dataset.id;
          const action = btn.dataset.action;
          if (action === 'edit') openLeadModal(db.leads.find(l => l.id === id));
          if (action === 'call') {
            const lead = db.leads.find(l => l.id === id);
            state.dialerCampaign = lead.campaign_id;
            state.page = 'dialer';
            state.forceLeadId = id;
            renderApp();
          }
          if (action === 'delete') {
            confirmAction('Excluir este lead?', 'Essa ação remove o lead, ligações e follow-ups relacionados.', () => {
              const lead = db.leads.find(l => l.id === id);
              db.leads = db.leads.filter(l => l.id !== id);
              db.callLogs = db.callLogs.filter(c => c.lead_id !== id);
              db.followUps = db.followUps.filter(f => f.lead_id !== id);
              saveDb();
              logActivity(`Lead removido: ${lead?.name || id}`);
              toast('Lead excluído.', 'success');
              renderLeads();
            });
          }
        });
      });
    }

