    function getDialerQueue(campaignId, search = '', resultFilter = 'all', openFilter = 'all') {
      const today = todayISO();
      const q = normalize(search || '');
      const digits = String(search || '').replace(/\D/g, '');
      const searchMode = !!(q || digits);

      // Filtro base: apenas leads da campanha selecionada e que podem ser discados
      let leads = filterLeads({ campaign: campaignId }).filter(l => isLeadActionableInDialer(l, searchMode));

      // Filtro de resultado (Especial: 'new' foca em 'Não contatado')
      if (resultFilter !== 'all') {
        leads = leads.filter(l => {
          const res = l.last_result || '';
          const status = l.crm_status || 'Não contatado';
          if (resultFilter === 'new') return status === 'Não contatado';
          if (resultFilter === 'Follow-up') return status === 'Follow-up' || res === 'Follow-up';
          return res === resultFilter;
        });
      }

      // Filtro de horário comercial
      if (openFilter !== 'all') {
        leads = leads.filter(l => isLeadOpenFilterMatch(l, openFilter));
      }

      // Filtro de busca textual ou numérica
      if (searchMode) {
        leads = leads.filter(l => {
          const text = normalize([
            l.name,
            l.phone,
            l.whatsapp,
            l.instagram,
            l.category,
            l.owner_name,
            l.attendant_name,
            l.crm_status,
            l.last_result
          ].join(' '));
          const phoneDigits = [l.phone, l.whatsapp].join(' ').replace(/\D/g, '');
          return (q && text.includes(q)) || (digits && phoneDigits.includes(digits));
        });
      }

      // Motor de Priorização (Core da Fila)
      const priority = l => {
        let score = 0;
        const issue = getLeadFlowIssue(l);
        
        // 1. Follow-ups atrasados (Máxima urgência)
        if (l.next_followup && isFollowupDue(l.next_followup)) {
          score += 1000;
          // Quanto mais atrasado, maior o score
          const diff = new Date() - new Date(l.next_followup);
          score += Math.min(diff / (1000 * 60 * 60), 500); // Até +500 pontos por horas de atraso
        }
        
        // 2. Leads Quentes
        if (l.temperature === 'Quente') score += 500;
        
        // 3. Pendências de fluxo (ex: follow-up sem data agendada)
        if (issue === 'Follow-up sem data') score += 300;
        
        // 4. Leads Novos (Não contatados)
        if (l.crm_status === 'Não contatado' && l.last_result !== 'Ligar Novamente') score += 100;
        
        // 5. Leads Mornos
        if (l.temperature === 'Morno') score += 50;
        
        // 6. Penalização para 'Ligar Novamente'
        if (l.last_result === 'Ligar Novamente') score -= 50;
        
        return score;
      };

      const sorted = leads.sort((a, b) => {
        const scoreA = priority(a);
        const scoreB = priority(b);
        if (scoreA !== scoreB) return scoreB - scoreA;
        
        // Empate: Ordem cronológica de entrada no CRM (ID)
        return (b.id > a.id) ? 1 : -1;
      });

      return applyDialerQueueOrder(sorted, campaignId, search);
    }

    function applyDialerQueueOrder(leads, campaignId = state.dialerCampaign, search = state.dialerSearch || '') {
      const context = state.dialerQueueContext || {};
      const sameContext =
        context.campaign === campaignId &&
        String(context.search || '') === String(search || '');

      if (!sameContext || !Array.isArray(state.dialerQueueOrder) || !state.dialerQueueOrder.length) {
        return leads;
      }

      const leadMap = new Map(leads.map(lead => [lead.id, lead]));
      const ordered = state.dialerQueueOrder
        .map(id => leadMap.get(id))
        .filter(Boolean);
      const orderedIds = new Set(ordered.map(lead => lead.id));
      const rest = leads.filter(lead => !orderedIds.has(lead.id));

      return ordered.length ? [...ordered, ...rest] : leads;
    }

    function moveCurrentDialerLeadDownFromQueue(leadId, queueBefore, positions = 10) {
      const ids = (queueBefore || [])
        .map(item => item && item.id)
        .filter(Boolean);

      const uniqueIds = [];
      ids.forEach(id => {
        if (!uniqueIds.includes(id)) uniqueIds.push(id);
      });

      const currentIndex = uniqueIds.indexOf(leadId);

      if (currentIndex === -1) {
        state.dialerQueueOrder = uniqueIds;
        state.dialerQueueContext = {
          campaign: state.dialerCampaign,
          search: state.dialerSearch || ''
        };
        return { order: uniqueIds, nextLeadId: uniqueIds[0] || '' };
      }

      uniqueIds.splice(currentIndex, 1);

      const targetIndex = Math.min(currentIndex + positions, uniqueIds.length);
      uniqueIds.splice(targetIndex, 0, leadId);

      const nextLeadId = uniqueIds[currentIndex] && uniqueIds[currentIndex] !== leadId
        ? uniqueIds[currentIndex]
        : (uniqueIds[currentIndex + 1] || uniqueIds[0] || '');

      state.dialerQueueOrder = uniqueIds;
      state.dialerQueueContext = {
        campaign: state.dialerCampaign,
        search: state.dialerSearch || ''
      };

      return {
        order: uniqueIds,
        nextLeadId
      };
    }

    function moveCurrentDialerLeadDown(leadId, positions = 10) {
      const queueBefore = getDialerQueue(state.dialerCampaign, state.dialerSearch || '');
      return moveCurrentDialerLeadDownFromQueue(leadId, queueBefore, positions);
    }

    function applyDialerPushDown(leads) {
      return leads;
    }

    function markLeadToDropInDialer(lead, positions = 10) {
      // Legado preservado para compatibilidade, mas não marca mais leads nem altera a fila.
      return lead;
    }

    function isLeadOpenFilterMatch(lead, filterValue) {
      if (!filterValue || filterValue === 'all') return true;
      const hours = getLeadBusinessHoursToday(lead);
      const isOpen = isBusinessOpen(hours);
      return filterValue === 'open' ? isOpen.open : !isOpen.open;
    }

    function clearLegacyDialerPushDownFlags() {
      let changed = false;

      (db.leads || []).forEach(lead => {
        if (!lead) return;

        if (lead.dialer_push_down || lead.dialer_push_down_at || lead.dialer_requeue_reason) {
          delete lead.dialer_push_down;
          delete lead.dialer_push_down_at;
          delete lead.dialer_requeue_reason;
          changed = true;
        }
      });

      if (changed) saveDb();
      return changed;
    }

    function repairNoAnswerQueueState() {
      let changed = false;
      const realCallLeadIds = new Set(
        (db.callLogs || [])
          .filter(call => isRealContactResult(call.result))
          .map(call => call.lead_id)
      );

      (db.leads || []).forEach(lead => {
        if (lead.last_result === 'Não atendeu') {
          lead.last_result = 'Ligar Novamente';
          changed = true;
        }

        // Correção preventiva: versões anteriores podiam transformar leads nunca ligados
        // em "Contato feito" por causa de resultado vazio tratado como contato real.
        // Só volta para "Não contatado" quando não existe resultado, último contato,
        // ligação real registrada ou follow-up com data.
        const hasNoRealContactEvidence =
          !String(lead.last_result || '').trim() &&
          !lead.last_contact &&
          !realCallLeadIds.has(lead.id) &&
          !lead.next_followup;

        if (hasNoRealContactEvidence && ['Contato feito','Follow-up','Oportunidade'].includes(lead.crm_status)) {
          lead.crm_status = 'Não contatado';
          clearDialerDrop(lead);
          changed = true;
        }

        if (normalizeLeadFlowState(lead)) changed = true;
      });
      if (changed) saveDb();
    }

    function renderDialerQueuePanel(queue, selectedLead) {
      const results = ['Follow-up', 'Reunião Marcada', 'Pediu WhatsApp', 'Falar com decisor', 'Não existe', 'Perdido'];
      const currentResultFilter = state.dialerResultFilter || 'all';
      const currentOpenFilter = state.dialerOpenFilter || 'all';
      
      return `<aside class="dialer-queue">
        <div class="dialer-queue-head">
          <h3>Fila de ligação</h3>
          <div class="grid grid-2" style="gap: 8px; margin-top: 10px;">
            <div class="field">
              <label style="font-size: 11px; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 4px; display: block;">Resultado</label>
              <select id="dialerResultFilter" class="select small" style="font-size: 12px; height: 34px; padding: 0 6px; min-width: 0;">
                <option value="all" ${currentResultFilter === 'all' ? 'selected' : ''}>Todos os leads</option>
                <option value="new" ${currentResultFilter === 'new' ? 'selected' : ''}>Não contatados</option>
                ${results.map(r => `<option value="${escapeAttr(r)}" ${currentResultFilter === r ? 'selected' : ''}>${r === 'Não existe' ? 'Número Inválido' : escapeHtml(r)}</option>`).join('')}
              </select>
            </div>
            <div class="field">
              <label style="font-size: 11px; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 4px; display: block;">Status</label>
              <select id="dialerOpenFilter" class="select small" style="font-size: 12px; height: 34px; padding: 0 6px; min-width: 0;">
                <option value="all" ${currentOpenFilter === 'all' ? 'selected' : ''}>Todos</option>
                <option value="open" ${currentOpenFilter === 'open' ? 'selected' : ''}>Abertos</option>
                <option value="closed" ${currentOpenFilter === 'closed' ? 'selected' : ''}>Fechados</option>
              </select>
            </div>
          </div>
          <p style="margin-top: 10px;">${state.dialerSearch ? `Busca: ${escapeHtml(state.dialerSearch)}` : 'Ordem real da fila.'}</p>
        </div>
        <div class="dialer-queue-body">
          ${queue.length ? queue.map(lead => renderQueueCard(lead, selectedLead?.id === lead.id)).join('') : `<div class="empty-state"><strong>Sem leads na fila</strong><span>Altere a campanha ou importe novos contatos.</span></div>`}
        </div>
      </aside>`;
    }

    function renderQueueCard(lead, active = false) {
      const campaignName = escapeHtml(getCampaign(lead.campaign_id).name);
      const isRetry = lead.last_result === 'Ligar Novamente';
      const isOverdue = lead.next_followup && isFollowupDue(lead.next_followup);
      const note = lead.next_followup ? `Follow-up: ${formatFollowupDateTime(lead.next_followup)}` : `Status: ${lead.crm_status || (lead.last_result ? lead.last_result : 'Não contatado')}`;
      const issue = getLeadFlowIssue(lead);
      const tempClass = lead.temperature === 'Quente' ? 'hot' : lead.temperature === 'Morno' ? 'warm' : lead.temperature === 'Frio' ? 'cold' : 'neutral';
      
      const hours = getLeadBusinessHoursToday(lead);
      const isOpen = isBusinessOpen(hours);
      const statusOpenClass = isOpen.open ? 'badge-success' : 'badge-danger';
      const statusOpenText = isOpen.open ? 'ABERTO' : 'FECHADO';


      return `<button type="button" class="queue-card ${active ? 'active' : ''}" data-queue-lead="${lead.id}">
        <div class="queue-card-top">
          <div>
            <div class="queue-card-name">${escapeHtml(lead.name)}</div>
            <div style="display:flex; align-items:center; gap:8px; margin-top:2px;">
               <div class="queue-card-phone">${escapeHtml(formatPhoneForDisplay(lead.phone) || '—')}${lead.whatsapp && lead.whatsapp !== lead.phone ? ` • WA: ${escapeHtml(formatPhoneForDisplay(lead.whatsapp))}` : ''}</div>
               <span class="badge ${statusOpenClass}" style="font-size:10px; padding:2px 6px;">${statusOpenText}</span>
            </div>
          </div>
          <div style="display:flex; align-items:center; gap:6px; margin-top:5px; flex-wrap:wrap;">
             <span class="queue-card-badge ${tempClass}">${lead.temperature || 'Morno'}</span>
             ${isOverdue ? '<span class="badge badge-danger" style="font-size:10px; padding:2px 6px;">ATRASADO</span>' : ''}
             ${isRetry ? '<span class="badge badge-warning" style="font-size:10px; padding:2px 6px;">REENTRADA</span>' : ''}
             ${issue ? `<span class="badge badge-danger" style="font-size:10px; padding:2px 6px;">${escapeHtml(issue)}</span>` : ''}
          </div>
        </div>
        <div class="queue-card-meta">${escapeHtml(lead.category || 'Sem categoria')} • ${campaignName}</div>
        <div class="queue-card-note" style="${isOverdue ? 'color:var(--danger); font-weight:700;' : ''}">${escapeHtml(note)}</div>
      </button>`;
    }

    function migrateDiagnosticData(diagnostic = {}) {
      const migrated = { ...diagnostic };
      if (!Array.isArray(migrated.questions)) {
        const questions = [];
        for (let i = 1; i <= 99; i++) {
          const question = migrated[`pergunta_${i}`] || '';
          const answer = migrated[`resposta_${i}`] || '';
          if (question || answer) questions.push({ number: i, question, answer });
        }
        migrated.questions = questions;
      }
      migrated.extras = migrated.extras || {};
      migrated.analysis = Array.isArray(migrated.analysis) ? migrated.analysis : [];
      migrated.transcript = migrated.transcript || '';
      migrated.data = migrated.data || '';
      migrated.periodo = migrated.periodo || '';
      migrated.horas = migrated.horas || '';
      migrated.followups = Array.isArray(migrated.followups) ? migrated.followups : [];
      return migrated;
    }

    function getDiagnosticQuestions(diagnostic = {}) {
      const migrated = migrateDiagnosticData(diagnostic);
      return (migrated.questions || []).map((item, index) => ({
        number: item.number || index + 1,
        question: item.question || item.pergunta || '',
        answer: item.answer || item.resposta || ''
      }));
    }

    function renderQAFields(questions = []) {
      const list = questions.length ? questions : [{ number: 1, question: '', answer: '' }];
      return list.map((item, index) => renderQAItem(item.question || '', item.answer || '', item.number || index + 1)).join('');
    }

    function renderQAItem(question = '', answer = '', number = 1) {
      return `<div class="qa-dynamic-item" data-qa-item>
        <div class="qa-dynamic-head">
          <strong>Pergunta ${number}</strong>
          <button type="button" class="btn small ghost" data-remove-qa title="Remover pergunta">Remover</button>
        </div>
        <div class="qa-dynamic-body">
          <div class="qa-grid">
            <div class="field">
              <label>Pergunta</label>
              <textarea class="textarea qa-question" placeholder="Pergunta feita...">${escapeHtml(question || '')}</textarea>
            </div>
            <div class="field">
              <label>Resposta</label>
              <textarea class="textarea qa-answer" placeholder="Resposta do lead...">${escapeHtml(answer || '')}</textarea>
            </div>
          </div>
        </div>
      </div>`;
    }

    function renderExtraFields(extras = {}) {
      const entries = Object.entries(extras || {});
      return entries.map(([key, value]) => renderExtraItem(key, value)).join('');
    }

    function renderExtraItem(key = '', value = '') {
      return `<div class="extra-dynamic-item" data-extra-item>
        <div class="field">
          <label>Campo</label>
          <input class="input extra-key" type="text" value="${escapeAttr(key)}" placeholder="Ex: OBJEÇÕES">
        </div>
        <div class="field">
          <label>Conteúdo</label>
          <textarea class="textarea extra-value" placeholder="Conteúdo salvo...">${escapeHtml(value || '')}</textarea>
        </div>
        <button type="button" class="btn small ghost" data-remove-extra title="Remover campo">Remover</button>
      </div>`;
    }

    function renderAnalysisFields(analysis = []) {
      const map = {};
      (analysis || []).forEach(item => {
        const key = normalizeAnalysisKey(item.key || item.title || '');
        if (key) map[key] = item;
      });
      return ANALYSIS_TYPES.map(type => {
        const item = map[type.key] || {};
        return renderAnalysisItem(type.key, item.text || item.value || '', item.score || '');
      }).join('');
    }

    function renderAnalysisItem(key = '', text = '', score = '') {
      const type = getAnalysisType(key) || { key, label: humanizeAnalysisKey(key), goal: '' };
      return `<div class="analysis-dynamic-item" data-analysis-item>
        <div class="analysis-dynamic-head">
          <strong>${escapeHtml(type.label)}</strong>
          <span class="score-pill">Tipo fixo</span>
        </div>
        <div class="analysis-dynamic-body">
          <div class="analysis-grid">
            <div class="field">
              <label>Tipo de análise</label>
              <input class="input analysis-key" type="text" value="${escapeAttr(type.key)}" readonly>
            </div>
            <div class="field">
              <label>Nota</label>
              <input class="input analysis-score" type="text" value="${escapeAttr(score)}" placeholder="Ex: 8/10">
            </div>
            <div class="field">
              <label>Descrição</label>
              <textarea class="textarea analysis-text" placeholder="${escapeAttr(type.goal || 'Análise do atendimento...')}">${escapeHtml(text || '')}</textarea>
            </div>
          </div>
        </div>
      </div>`;
    }

    function renumberQAItems() {
      document.querySelectorAll('[data-qa-item]').forEach((item, index) => {
        const title = item.querySelector('.qa-dynamic-head strong');
        if (title) title.textContent = `Pergunta ${index + 1}`;
      });
    }

    function collectQuestionFields() {
      return [...document.querySelectorAll('[data-qa-item]')].map((item, index) => {
        const question = item.querySelector('.qa-question')?.value.trim() || '';
        const answer = item.querySelector('.qa-answer')?.value.trim() || '';
        return { number: index + 1, question, answer };
      }).filter(item => item.question || item.answer);
    }

    function collectExtraFields() {
      const extras = {};
      document.querySelectorAll('[data-extra-item]').forEach(item => {
        const key = (item.querySelector('.extra-key')?.value || '').trim();
        const value = (item.querySelector('.extra-value')?.value || '').trim();
        if (key && value) extras[key] = value;
      });
      return extras;
    }

    function collectAnalysisFields() {
      return [...document.querySelectorAll('[data-analysis-item]')].map(item => ({
        key: normalizeAnalysisKey((item.querySelector('.analysis-key')?.value || '').trim()),
        score: (item.querySelector('.analysis-score')?.value || '').trim(),
        text: (item.querySelector('.analysis-text')?.value || '').trim()
      })).filter(item => item.key || item.score || item.text);
    }

    function humanizeAnalysisKey(key = '') {
      return String(key || '')
        .replace(/_/g, ' ')
        .toLowerCase()
        .replace(/(^|\s)\S/g, letter => letter.toUpperCase());
    }

    function parseLeadSocialMedia(lead) {
      if (!lead || !lead.social_media) return {};
      if (typeof lead.social_media === 'object') return lead.social_media;
      try {
        return JSON.parse(lead.social_media);
      } catch (e) {
        return {};
      }
    }

    function normalizeUrl(url) {
      const value = String(url || '').trim();
      if (!value) return '';
      if (/^https?:\/\//i.test(value)) return value;
      if (/^www\./i.test(value)) return `https://${value}`;
      return '';
    }

    function getInstagramUrl(lead) {
      const social = parseLeadSocialMedia(lead);
      const raw = String(lead?.instagram || social.instagram || '').trim();
      if (!raw) return '';

      if (/^https?:\/\//i.test(raw)) return raw;
      const clean = raw.replace(/^@/, '').replace(/^instagram\.com\//i, '').replace(/^www\.instagram\.com\//i, '').split(/[/?#]/)[0];
      return clean ? `https://instagram.com/${clean}` : '';
    }

    function getWebsiteUrl(lead) {
      const social = parseLeadSocialMedia(lead);
      const candidates = [
        lead?.website,
        lead?.site,
        lead?.url,
        social.website,
        social.site,
        social.url
      ];
      for (const candidate of candidates) {
        const url = normalizeUrl(candidate);
        if (url && !/instagram\.com|wa\.me|whatsapp|google\.com\/maps|googleusercontent/i.test(url)) return url;
      }
      return '';
    }

    function renderLeadExternalButtons(lead) {
      const instagramUrl = getInstagramUrl(lead);
      const websiteUrl = getWebsiteUrl(lead);
      return `
        ${instagramUrl ? `<a class="dialer-action-btn external-link" target="_blank" rel="noopener noreferrer" class="external-link" href="${escapeAttr(instagramUrl)}">📸 Instagram</a>` : ''}
        ${websiteUrl ? `<a class="dialer-action-btn external-link" target="_blank" rel="noopener noreferrer" class="external-link" href="${escapeAttr(websiteUrl)}">🌐 Site</a>` : ''}
      `;
    }

    function getLeadBusinessHoursToday(lead) {
      if (!lead) return '';
      const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
      const today = new Date().getDay();
      const key = `hours_${dayNames[today]}`;
      return lead[key] || '';
    }

    function isBusinessOpen(hoursStr) {
      if (!hoursStr || hoursStr === '—') return { open: false, msg: 'Horário não informado' };
      
      const now = new Date();
      const currentMinutes = now.getHours() * 60 + now.getMinutes();
      
      // Basic parser for "11am-3am" or "11am-12am"
      const parts = hoursStr.toLowerCase().replace(/\s/g, '').split('-');
      if (parts.length !== 2) return { open: true, msg: hoursStr }; 

      const parseTime = (t) => {
        let m = t.match(/(\d+)(am|pm)?/);
        if (!m) return 0;
        let h = parseInt(m[1]);
        let ampm = m[2];
        if (ampm === 'pm' && h < 12) h += 12;
        if (ampm === 'am' && h === 12) h = 0;
        return h * 60;
      };

      let start = parseTime(parts[0]);
      let end = parseTime(parts[1]);

      if (end <= start) {
        if (currentMinutes >= start || currentMinutes < end) return { open: true, msg: hoursStr };
      } else {
        if (currentMinutes >= start && currentMinutes < end) return { open: true, msg: hoursStr };
      }

      return { open: false, msg: hoursStr };
    }

