    function getAllAudioItems() {
      const items = [];
      const pushAudio = (audio, meta = {}) => {
        if (!audio) return;
        const dataUrl = normalizeAudioDataUrl(audio) || audio.data_url || audio.audio_data_url || audio.dataUrl || '';
        if (!dataUrl) return;
        items.push({ audio, dataUrl, meta });
      };
      (db.leads || []).forEach(lead => {
        pushAudio(lead.call_audio, { origin: 'lead.call_audio', lead });
        (Array.isArray(lead.audio_backups) ? lead.audio_backups : []).forEach((audio, index) => pushAudio(audio, { origin: `lead.audio_backups[${index}]`, lead }));
        (Array.isArray(lead.audios) ? lead.audios : []).forEach((audio, index) => pushAudio(audio, { origin: `lead.audios[${index}]`, lead }));
      });
      (db.callLogs || []).forEach(call => {
        const lead = (db.leads || []).find(l => l.id === call.lead_id) || null;
        pushAudio(call.audio, { origin: 'db.callLogs.audio', lead, call });
        pushAudio(call.call_audio, { origin: 'db.callLogs.call_audio', lead, call });
        pushAudio(call.audio_meta, { origin: 'db.callLogs.audio_meta', lead, call });
        if (call.audio_data_url) pushAudio({ data_url: call.audio_data_url, name: call.audio_filename || 'audio-ligacao.mp3', type: call.audio_mime || 'audio/mpeg', size: call.audio_size || 0 }, { origin: 'db.callLogs.audio_data_url', lead, call });
      });
      (Array.isArray(db.orphanAudios) ? db.orphanAudios : []).forEach((audio, index) => pushAudio(audio, { origin: `db.orphanAudios[${index}]`, lead: null, orphan: true }));
      return items;
    }

    function simpleAudioHash(dataUrl, name = '', size = '') {
      const text = `${name}|${size}|${String(dataUrl || '').slice(0, 120)}|${String(dataUrl || '').slice(-80)}`;
      let hash = 0;
      for (let i = 0; i < text.length; i++) hash = ((hash << 5) - hash + text.charCodeAt(i)) | 0;
      return `aud_${Math.abs(hash)}`;
    }

