    async function handleSettingsBackupFile(event, forcedType = 'auto') {
      const input = event.target;
      const file = input.files?.[0];
      if (!file) return;
      input.value = '';
      showLoading(true);
      try {
        const raw = await file.text();
        const preview = detectImportPreview(file, raw, forcedType);
        showLoading(false);
        openSettingsImportPreview(preview);
      } catch (error) {
        showLoading(false);
        toast(`Não consegui ler o arquivo: ${error.message || 'arquivo inválido'}`, 'error');
        appendSettingsHistory('Erro de importação', error.message || 'Falha ao ler arquivo.', { file: file.name || '', status: 'Erro' });
      }
    }

    function detectImportPreview(file, raw, forcedType = 'auto') {
      const name = file?.name || 'arquivo';
      const lower = name.toLowerCase();
      const preview = {
        fileName: name,
        raw,
        forcedType,
        type: 'Incompatível',
        warnings: [],
        counts: { leads: 0, campaigns: 0, calls: 0, followUps: 0, meetings: 0, transcriptions: 0, audios: 0, newEstimate: 0, existingEstimate: 0, duplicates: 0, conflicts: 0 },
        payload: null
      };
      if (!raw || !String(raw).trim()) throw new Error('Arquivo vazio.');
      if (forcedType === 'audio') {
        const parsed = JSON.parse(raw || '{}');
        if (!isAudioBackupPayload(parsed)) throw new Error('Arquivo não parece backup de áudio do BuyFlow.');
        preview.type = 'Backup de áudio';
        preview.payload = parsed;
        preview.counts.audios = Array.isArray(parsed.audios) ? parsed.audios.length : 0;
        return preview;
      }
      if (lower.endsWith('.csv') || /^\s*"?Nome da empresa|^\s*"?crm_internal_id|^\s*"?company_name/i.test(raw)) {
        const rows = parseCSV(sanitizeCsvText(raw));
        if (!rows.length) throw new Error('CSV vazio ou corrompido.');
        const headerInfo = detectHeaderRow(rows);
        const headers = headerInfo.headers || [];
        preview.type = isRestorableBackupCSVHeaders(headers) ? 'CSV completo do CRM' : 'CSV comum de leads';
        preview.counts.leads = Math.max(0, rows.length - headerInfo.rowIndex - 1);
        preview.counts.newEstimate = preview.counts.leads;
        if (preview.type === 'CSV completo do CRM') {
          const snapshot = buildRestorableBackupCSVSnapshot(raw, name);
          preview.payload = snapshot;
          preview.counts.leads = snapshot.leads.length;
          preview.counts.calls = snapshot.callLogs.length;
          preview.counts.followUps = snapshot.followUps.length;
          preview.counts.meetings = snapshot.meetings.length;
          preview.counts.transcriptions = snapshot.leads.filter(l => getLeadTranscript(l)).length;
        } else {
          preview.warnings.push('CSV comum: será aberto no fluxo de mapeamento para escolher campanha e colunas antes de salvar.');
        }
        return preview;
      }
      const parsed = JSON.parse(raw || '{}');
      if (isAudioBackupPayload(parsed)) {
        preview.type = 'Backup de áudio';
        preview.payload = parsed;
        preview.counts.audios = Array.isArray(parsed.audios) ? parsed.audios.length : 0;
        return preview;
      }
      const data = getRestorableBackupDataFromJSON(parsed);
      const summary = summarizeBackupDataForImport(data);
      preview.type = 'JSON restaurável sem áudio';
      preview.payload = data;
      preview.counts.leads = summary.leads;
      preview.counts.campaigns = summary.campaigns;
      preview.counts.calls = summary.calls;
      preview.counts.followUps = summary.followUps;
      preview.counts.meetings = summary.meetings;
      preview.counts.transcriptions = (data.leads || []).filter(l => l.call_transcript || l.diagnostic_data?.transcript).length;
      preview.counts.newEstimate = summary.leads;
      return preview;
    }

    function openSettingsImportPreview(preview) {
      const c = preview.counts || {};
      openModal(`
        <div class="modal-header"><div class="modal-title-wrap"><div class="modal-icon orange">📥</div><div><h2>Prévia antes de importar</h2><p>Cancelar não altera nada. Confirmar executa a mesclagem segura.</p></div></div><button type="button" class="btn ghost modal-close" data-close>✕</button></div>
        <div class="modal-body">
          <div class="settings-card featured"><div class="settings-card-top"><div class="settings-icon">🔎</div><div><h4>${escapeHtml(preview.fileName)}</h4><p>Tipo detectado: <strong>${escapeHtml(preview.type)}</strong></p></div></div></div>
          <div class="settings-import-preview-list">
            ${[['Leads encontrados', c.leads], ['Campanhas', c.campaigns], ['Ligações', c.calls], ['Follow-ups', c.followUps], ['Reuniões', c.meetings], ['Transcrições', c.transcriptions], ['Áudios', c.audios], ['Novos estimados', c.newEstimate], ['Possíveis já existentes', c.existingEstimate], ['Possíveis duplicados', c.duplicates], ['Possíveis conflitos', c.conflicts]].map(([label, value]) => `<div class="settings-stat"><small>${escapeHtml(label)}</small><strong>${Number(value || 0)}</strong></div>`).join('')}
          </div>
          <div class="settings-note">A importação mescla os dados do arquivo com a base atual. O CRM mantém o que já existe, adiciona novos registros e atualiza registros iguais sem apagar histórico.</div>
          ${preview.warnings?.length ? `<div class="settings-note">${preview.warnings.map(escapeHtml).join('<br>')}</div>` : ''}
        </div>
        <div class="modal-footer"><button type="button" class="btn secondary" data-close>Cancelar</button><button id="confirmSettingsImportBtn" type="button" class="btn success">Confirmar importação</button></div>
      `, 'details-modal');
      document.getElementById('confirmSettingsImportBtn')?.addEventListener('click', () => confirmSettingsImport(preview));
    }

    function confirmSettingsImport(preview) {
      showLoading(true);
      try {
        let stats = null;
        if (preview.type === 'CSV comum de leads') {
          showLoading(false);
          closeModal();
          openImportModal();
          toast('CSV comum aberto no fluxo de mapeamento. Selecione o arquivo novamente para confirmar campanha e colunas.', 'warning');
          return;
        }
        if (preview.type === 'CSV completo do CRM') {
          stats = applyRestorableBackupSnapshot(preview.payload);
        } else if (preview.type === 'Backup de áudio') {
          stats = importAudioBackupData(preview.payload, preview.fileName);
        } else if (preview.type === 'JSON restaurável sem áudio') {
          stats = mergeRestorableBackupDataIntoCurrent(preview.payload, preview.fileName);
        } else {
          throw new Error('Tipo de arquivo incompatível.');
        }
        ensureSettings();
        db.settings.lastImportAt = new Date().toISOString();
        appendSettingsHistory('Importação', `${preview.type} importado/mesclado com sucesso.`, { file: preview.fileName, status: 'OK' });
        saveDb();
        showLoading(false);
        toast('Importação mesclada com segurança.', 'success');
        renderApp();
      } catch (error) {
        showLoading(false);
        appendSettingsHistory('Erro de importação', error.message || 'Falha ao importar.', { file: preview.fileName, status: 'Erro' });
        toast(`Não consegui importar: ${error.message || 'arquivo inválido'}`, 'error');
      }
    }

