    function createSettingsMathChallenge() {
      const a = Math.floor(Math.random() * 8) + 2;
      const b = Math.floor(Math.random() * 8) + 2;
      state.crmResetMathChallenge = { a, b, answer: a + b, created_at: new Date().toISOString() };
      return state.crmResetMathChallenge;
    }

    function openSettingsCrmResetChallenge() {
      const challenge = createSettingsMathChallenge();
      openModal(`
        <div class="modal-header">
          <div class="modal-title-wrap">
            <div class="modal-icon red">🔒</div>
            <div><h2>Formatar CRM 100% com trava</h2><p>Essa ação é protegida por conta matemática para evitar clique acidental.</p></div>
          </div>
          <button type="button" class="btn ghost modal-close" data-close>✕</button>
        </div>
        <div class="modal-body">
          <div class="crm-reset-lockbox">
            <strong>Confirmar formatação total do CRM</strong>
            <p style="margin:0;color:var(--muted);line-height:1.55;">Isso vai apagar todos os dados locais deste navegador e deixar a base zerada, sem leads, campanhas, ligações, follow-ups, reuniões, metas, análises, importações, áudios ou histórico. Faça backup antes se tiver dados importantes.</p>
            <div class="crm-reset-warning"><strong>Atenção:</strong> depois de confirmar, o CRM ficará 100% limpo, sem dados de teste e sem registros antigos.</div>
            <div class="crm-reset-math">
              <div class="crm-reset-equation"><small>Responda para liberar</small><b>${challenge.a} + ${challenge.b} = ?</b></div>
              <div class="field"><label>Resultado da conta</label><input id="crmResetMathAnswer" class="input" type="number" inputmode="numeric" placeholder="Digite a resposta"></div>
            </div>
          </div>
        </div>
        <div class="modal-footer">
          <button id="crmResetCancelMathBtn" type="button" class="btn secondary">Cancelar</button>
          <button id="crmResetConfirmMathBtn" type="button" class="btn danger">Confirmar e formatar CRM</button>
        </div>
      `, 'confirm-modal');
      requestAnimationFrame(() => {
        const input = document.getElementById('crmResetMathAnswer');
        bindOnce('crmResetCancelMathBtn', 'click', () => closeModal());
        bindOnce('crmResetConfirmMathBtn', 'click', () => confirmSettingsCrmResetChallenge());
        if (input) {
          input.focus({ preventScroll: true });
          input.addEventListener('keydown', event => {
            if (event.key === 'Enter') {
              event.preventDefault();
              confirmSettingsCrmResetChallenge();
            }
          });
        }
      });
    }

    function confirmSettingsCrmResetChallenge() {
      const challenge = state.crmResetMathChallenge || {};
      const rawAnswer = document.getElementById('crmResetMathAnswer')?.value;
      const answer = Number(rawAnswer);
      if (!Number.isFinite(answer) || answer !== Number(challenge.answer)) {
        toast('Conta incorreta. O CRM não foi formatado.', 'error');
        const input = document.getElementById('crmResetMathAnswer');
        if (input) { input.value = ''; input.focus({ preventScroll: true }); }
        return;
      }
      db = createEmptyFormattedDb();
      state.selectedDialerLeadId = '';
      state.dialerQueueOrder = [];
      state.lastDialerUndo = null;
      state.lastDialerRedo = null;
      sessionStorage.setItem('buyflow_current_user', db.users[0].id);
      state.currentUser = db.users[0];
      localStorage.removeItem(STORAGE_KEY);
      saveDb();
      closeModal();
      toast('CRM formatado. A base ficou limpa, sem dados de teste.', 'success');
      renderApp();
    }

