          <div class="follow-alert-card warning"><div class="follow-alert-top"><small>Fila atual</small><span class="follow-icon">🎯</span></div><strong>${isSearching ? `${queue.length}/${allQueue.length}` : queue.length}</strong><span>${isSearching ? 'Resultado da busca dentro da fila.' : 'Leads disponíveis para ligar.'}</span></div>
