  window.bfEnhanceCurrentPageFilters = function bfEnhanceCurrentPageFilters() {
    const content = document.getElementById('content');
    if (!content) return;
    try {
      const page = typeof state !== 'undefined' ? state.page : '';

      if (page === 'leads' || document.getElementById('leadCampaign')) bfEnhanceLeads(content);
      if (page === 'dialer' || document.getElementById('dialerCampaign') || document.getElementById('dialerResultFilter')) bfEnhanceDialer(content);
      if (page === 'followups' || document.getElementById('followCampaign')) bfEnhanceFollowups(content);
      if (page === 'contacts' || document.getElementById('contactCampaign')) bfEnhanceContacts(content);
      if (page === 'meetings' || document.getElementById('meetingCampaign')) bfEnhanceMeetings(content);
      if (page === 'campaigns' || document.getElementById('campaignSearchInput')) bfEnhanceCampaigns(content);
      if (page === 'pipeline' || document.getElementById('pipelineSearch')) bfEnhancePipeline(content);
      if (page === 'analysis' || document.getElementById('analysisCampaign')) bfEnhanceAnalysis(content);
      if (page === 'goals' || document.getElementById('goalFilterPeriod')) bfEnhanceGoals(content);

      setupBuyFlowCustomSelects(content);
    } catch (error) {
      console.error('Erro ao aplicar filtros customizados BuyFlow:', error);
    }
  };

  if (typeof renderGoals === 'function' && !renderGoals.__bfGoalsSmartFilterWrapped) {
    const originalRenderGoals = renderGoals;
    renderGoals = function renderGoalsWithSmartMetaFilter() {
      const result = originalRenderGoals.apply(this, arguments);
      requestAnimationFrame(() => {
        const content = document.getElementById('content');
        if (!content) return;
        try {
          bfEnhanceGoals(content);
          setupBuyFlowCustomSelects(content);
        } catch (error) {
          console.error('Erro ao reaplicar filtro de Metas:', error);
        }
      });
      return result;
    };
    renderGoals.__bfGoalsSmartFilterWrapped = true;
  }

